CREATE DATABASE IF NOT EXISTS moj_judicial CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci; USE moj_judicial;
CREATE TABLE roles(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) UNIQUE NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE permissions(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE NOT NULL) ENGINE=InnoDB;
CREATE TABLE users(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,role_id BIGINT UNSIGNED NULL,name VARCHAR(160) NOT NULL,email VARCHAR(190) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,remember_token VARCHAR(100),login_attempts INT DEFAULT 0,locked_until DATETIME NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(role_id) REFERENCES roles(id)) ENGINE=InnoDB;
CREATE TABLE cities(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(160) UNIQUE NOT NULL) ENGINE=InnoDB;
CREATE TABLE courts(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,city_id BIGINT UNSIGNED NULL,name VARCHAR(255) NOT NULL,type VARCHAR(120),UNIQUE KEY uq_court(name,city_id),FOREIGN KEY(city_id) REFERENCES cities(id)) ENGINE=InnoDB;
CREATE TABLE subjects(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255) UNIQUE NOT NULL) ENGINE=InnoDB;
CREATE TABLE keywords(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(190) UNIQUE NOT NULL) ENGINE=InnoDB;
CREATE TABLE judicial_decisions(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,external_id VARCHAR(190) UNIQUE NOT NULL,decision_number VARCHAR(190),title VARCHAR(500) NOT NULL,court_id BIGINT UNSIGNED NULL,subject_id BIGINT UNSIGNED NULL,court_name VARCHAR(255),city_name VARCHAR(160),court_type VARCHAR(120),circuit VARCHAR(255),judge_name VARCHAR(255),decision_date DATE NULL,subject VARCHAR(255),legal_articles JSON NULL,summary TEXT,full_text LONGTEXT,source_url VARCHAR(1000),content_hash CHAR(64) NOT NULL,raw_json JSON NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(court_id) REFERENCES courts(id),FOREIGN KEY(subject_id) REFERENCES subjects(id),INDEX idx_decision_number(decision_number),INDEX idx_date(decision_date),INDEX idx_court(court_name),FULLTEXT KEY ft_decision(title,summary,full_text,subject)) ENGINE=InnoDB;
CREATE TABLE decision_keywords(decision_id BIGINT UNSIGNED NOT NULL,keyword_id BIGINT UNSIGNED NOT NULL,PRIMARY KEY(decision_id,keyword_id),FOREIGN KEY(decision_id) REFERENCES judicial_decisions(id) ON DELETE CASCADE,FOREIGN KEY(keyword_id) REFERENCES keywords(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE attachments(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,decision_id BIGINT UNSIGNED NOT NULL,name VARCHAR(255),url VARCHAR(1000),mime VARCHAR(100),size BIGINT,FOREIGN KEY(decision_id) REFERENCES judicial_decisions(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE crawler_logs(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,level VARCHAR(20),message TEXT,context JSON,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE crawler_errors(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,decision_external_id VARCHAR(190),error TEXT,trace MEDIUMTEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE settings(`key` VARCHAR(190) PRIMARY KEY,`value` TEXT,autoload TINYINT(1) DEFAULT 1) ENGINE=InnoDB;
CREATE TABLE favorites(user_id BIGINT UNSIGNED,decision_id BIGINT UNSIGNED,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(user_id,decision_id),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(decision_id) REFERENCES judicial_decisions(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE search_history(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NULL,query VARCHAR(500),filters JSON,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE api_logs(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,endpoint VARCHAR(255),method VARCHAR(10),status INT,duration_ms INT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX idx_endpoint(endpoint)) ENGINE=InnoDB;
CREATE TABLE cache(`key` VARCHAR(190) PRIMARY KEY,`value` MEDIUMBLOB,expires_at DATETIME NOT NULL,INDEX idx_expires(expires_at)) ENGINE=InnoDB;
DELIMITER //
CREATE TRIGGER trg_decisions_hash BEFORE UPDATE ON judicial_decisions FOR EACH ROW BEGIN IF NEW.content_hash <> OLD.content_hash THEN SET NEW.updated_at=CURRENT_TIMESTAMP; END IF; END//
CREATE PROCEDURE sp_decision_counts() BEGIN SELECT COUNT(*) decisions, COUNT(DISTINCT court_name) courts, COUNT(DISTINCT city_name) cities, COUNT(DISTINCT subject) subjects FROM judicial_decisions; END//
DELIMITER ;
CREATE OR REPLACE VIEW v_latest_decisions AS SELECT id,decision_number,title,court_name,decision_date,created_at FROM judicial_decisions ORDER BY created_at DESC LIMIT 100;
CREATE OR REPLACE VIEW v_import_errors AS SELECT DATE(created_at) day, COUNT(*) errors FROM crawler_errors GROUP BY DATE(created_at);
